@ARTICLE{10.1111/aor.14494,
	author = {Leon SA and Rosen JL and Ahmad D and Austin MA and Vishnevsky A and Rajapreyar IN and Ruggiero NJ and Rame JE and Entwistle JW and Massey HT and Tchantchaleishvili V},
	title = {Microaxial circulatory support for percutaneous coronary intervention: A systematic review and meta-analysis.},
	journal = {Artif Organs},
	year = {2023},
	abstract = {BACKGROUND: Microaxial circulatory support devices have been used to support patients treated with percutaneous coronary intervention (PCI) for acute myocardial infarction complicated by cardiogenic shock (AMICS). The purpose of this systematic review and meta-analysis was to pool and analyze the existing evidence on the baseline characteristics, periprocedural data, and outcomes of microaxial support before and after PCI in AMICS. METHODS: An electronic database search was performed to identify all cohort studies on Impella and PCI for cardiogenic shock in the English language. A total of five articles comprising 543 patients were included. These patients received microaxial support either before (pre-PCI) or after (post-PCI) undergoing PCI. Comparative analyses were done between both groups. RESULTS: The mean patient age was 66 years [95% Confidence Interval (58-74)], and 22% (89/396) of patients were female. ST-elevation myocardial infarctions (MI) comprised 64% (44-80) of MIs and 50% (44-56) of MIs involved the left anterior descending artery. The mean number of diseased vessels was 2.21 (1.62-2.80). The mean left ventricular ejection fraction was 31% (23.4-38.6). The mean arterial pressure was 66.3 mm Hg (54.1-78.5). Mean serum lactate [6.1 mmol/L (3.3-8.9)] and serum creatinine [1.4 mg/dl (1.0-1.7)] were similar between groups. 30-day mortality was lower in the pre-PCI group [41% (34%-49%)] compared to the post-PCI group [61% (42%-77%), p < 0.01]. Pooled Kaplan-Meier analysis showed better early survival in the pre-PCI group (p < 0.001). CONCLUSION: Patients presenting with AMICS were similar at baseline in both pre-PCI and post-PCI groups. Nevertheless, pre-PCI group showed better early survival compared to post-PCI group.},
	doi = {10.1111/aor.14494},
	pmid = {36691820 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.healun.2022.12.007,
	author = {Boccellino A and Sacchi S and Pazzanese V and Calvo F and Gramegna M and Ingallina G and Cappelletti A and Baldetti L},
	title = {Effects of Intra-Aortic Balloon Pump delayed deflation timing on carotid blood flow and cardiac mechanics: An ultrasound and haemodynamic study.},
	journal = {J Heart Lung Transplant},
	year = {2023},
	abstract = {Intra-Aortic Balloon Pump (IABP) efficacy is critically affected by the inflation/deflation timing. Balloon deflation may cause a sucking effect, and a steal phenomenon on carotid flow. Delaying IABP deflation reduces the degree of this flow reversal, but at the same time exposes patients to the risk of increased proto-systolic afterload with detrimental effects on the LV. The purpose of this study was to investigate the effects of a delayed IABP deflation timing on cerebral blood flow and LV hemodynamics, by means of simultaneous carotid artery ultrasonography, trans-thoracic echocardiography and central aortic pressure analysis. Delaying IABP deflation trigger to the beginning of QRS effectively increased the cerebral blood flow by 20%, mostly by reducing the reverse component flow caused by the diastolic balloon deflation. Extending the deflation to the early systole was safe and favourably impacted on cardiac mechanics, increasing CO by 15% without prolonging LV isovolumetric contraction and ejection phases.},
	doi = {10.1016/j.healun.2022.12.007},
	pmid = {36682892 [Indexed for MEDLINE]}
}

@ARTICLE{10.2169/internalmedicine.0796-22,
	author = {Izumida T and Kataoka N and Imamura T and Uchida K and Koi T and Nakagaito M and Nakamura M and Komatsu Y and Nogami A and Kinugawa K},
	title = {Bail-out Ablation of Ventricular Tachycardia Electrical Storm in a Patient with a Durable Left Ventricular Assist Device.},
	journal = {Intern Med},
	year = {2023},
	abstract = {The therapeutic strategy for sustained ventricular tachycardia (VT) during left ventricular assist device usage remains unclear. We encountered a patient with durable left ventricular assist device who presented sustained VT. Electrophysiological mapping was able to be established appropriately owing to the robust mechanical hemodynamics support despite inter-device interference. The three-dimensional activation map of clinically documented VT demonstrated that the propagation exited from the right ventricular apex through the critical isthmus located at the epicardium or interventricular septum, which was successfully treated by catheter ablation at the exit site. Further experiences like ours should be accumulated to establish a therapeutic strategy.},
	doi = {10.2169/internalmedicine.0796-22},
	pmid = {36476550 [Indexed for MEDLINE]},
	note = {PMC10465274}
}

@ARTICLE{10.1055/s-0042-1757300,
	author = {Pausch J and Mersmann J and Bhadra OD and Barten MJ and Alassar YA and Schulte-Uentrop L and Reichenspurner H and Bernhardt AM},
	title = {Preliminary Experience of Extracorporeal Cytokine Hemoadsorption during Left Ventricular Assist Device Implantation in Cardiogenic Shock Patients.},
	journal = {Thorac Cardiovasc Surg},
	year = {2024},
	abstract = {BACKGROUND: Systemic inflammation due to cardiogenic shock is associated with vasoplegia leading to organ hypoperfusion, right heart failure, and poor clinical outcome. Extracorporeal cytokine hemoadsorption emerged to attenuate excessive levels of inflammatory cytokines, potentially improving patient outcomes. Nevertheless, its prognostic impact during high-risk left ventricular assist device (LVAD) implantation remains unknown. METHODS: In total, 40 consecutive patients with advanced heart failure underwent continuous-flow LVAD implantation at our institution between 2018 and 2020. Out of 25 high-risk patients in cardiogenic shock (Interagency Registry for Mechanically Assisted Circulatory Support profile 1 and 2), 9 patients (CytoSorb group) underwent LVAD implantation with and 16 patients (control group) without simultaneous cytokine hemoadsorption during cardiopulmonary bypass. Besides preoperative patient characteristics, postoperative lactate clearance, vasopressor administration and mean arterial pressure, perioperative complication, and 30-day mortality rates were retrospectively analyzed. RESULTS: Apart from an increased rate of reoperations within the CytoSorb group, baseline characteristics including the severity of ventricular dysfunction and consecutive signs of end-organ failure were similar in both groups. Preoperative short-term mechanical circulatory support bridging was comparable (66.7 vs. 75%; p = 0.66) prior to LVAD implantation. Procedural characteristics including intraoperative volume management and postoperative vasopressor administration were similar in both groups. There was no difference regarding postoperative lactate clearance, although postoperative mean arterial pressure was significantly higher in the control group (71.3 vs. 57.4 mm Hg; p < 0.01). Furthermore, the 30-day mortality rate was significantly higher in the CytoSorb group (33.3 vs. 0.0%; p = 0.01). CONCLUSION: Extracorporeal cytokine hemoadsorption during high-risk LVAD implantation was not associated with a decrease of postoperative vasopressor support, improved hemodynamics, or an accelerated lactate clearance.},
	doi = {10.1055/s-0042-1757300},
	pmid = {36216331 [Indexed for MEDLINE]}
}

@ARTICLE{10.1371/journal.pone.0273108,
	author = {Slade AL and O'Hara ME and Quinn D and Marley L and Griffith S and Calvert M and Haque MS and Lim HS and Doherty P and Lane DA},
	title = {Living with a left ventricular assist device: Capturing recipients experiences using group concept mapping software.},
	journal = {PLoS One},
	year = {2022},
	abstract = {BACKGROUND: Left ventricular assist device (LVAD) implantation significantly impacts on a recipient's symptoms and quality of life. Capturing their experiences and post implant journey is an important part of clinical practice, research and device design evolution. Patient reported outcome measures (PROMs) are a useful tool for capturing that experience. However, patient reported outcome measures need to reflect recipients' experiences. Discussions with a patient partner group found that none of the frequently used cardiology PROMs captured their unique experiences. AIMS: To capture the experiences and important issues for LVAD recipients. Develop a conceptual map of domains and items that should be reflected in patient reported outcomes. METHODS: Group concept mapping (GCM) web-based software was used to remotely capture and structure recipients' experiences across a wide geographical area. GCM is a semi-quantitative mixed method consisting of 3 stages: item generation, item sorting and rating (importance, relevance and frequency). Patient partners were involved in all aspects of the study design and development. RESULTS: 18 LVAD recipients consented to take part. 101 statements were generated and multi-dimensional scaling, and hierarchical cluster analysis identified 9 clusters. Cluster themes included: Activities, Partner/family support, Travel, Mental wellbeing, Equipment and clothing, Physical and cognitive limitations, LVAD Restrictions, LVAD Challenges and positive impact of the LVAD (LVAD Positives). LVAD Positives were scored highest across all the rating variables, e.g., frequency (2.85), relevance (2.44) and importance (2.21). Other domains rated high for importance included physical and cognitive limitations (2.19), LVAD restrictions (2.11), Partner/family support (2.02), and Equipment and clothing (2.01). CONCLUSION: Online GCM software facilitated the inclusion of geographically dispersed recipients and provided useful insights into the experiences of LVAD recipients. The conceptual framework identifies important domains and items that should be prioritised and included in patient reported outcomes in future research, LVAD design evolution, and clinical practice.},
	doi = {10.1371/journal.pone.0273108},
	pmid = {36129928 [Indexed for MEDLINE]},
	note = {PMC9491568}
}
